would it make sense to wrap that up into a helper function somewhere under test/e2e and have all the call-sites call that instead:
// VerifyConformantResourceVersions ensures oldRV compares older than newRV without errors,
// and that both oldRV and newRV fit within allowed bit lengths described in KEP-5504.
func VerifyConformantResourceVersions(oldRV, newRV string) {
	// oldRV must compare less than newRV without errors
	gomega.Expect(resourceversion.CompareResourceVersion(oldRV, newRV)).To(gomega.BeNumerically("==", -1), "oldRV must compare older than newRV")

	// oldRV must be <= 128 bits long
	oldRVInt, err := big.NewInt(0).SetString(oldRV, 10)
	gomega.Expect(err).To(gomega.BeNil())
	gomega.Expect(oldRVInt.BitLen()).To(gomega.BeNumerically("<=", 128), "oldRV must be <= 128 bits long")

	// newRV must be <= 128 bits long
	newRVInt, err := big.NewInt(0).SetString(newRV, 10)
	gomega.Expect(err).To(gomega.BeNil())
	gomega.Expect(newRVInt.BitLen()).To(gomega.BeNumerically("<=", 128), "newRV must be <= 128 bits long")
}

